// NewGenerator creates a new Generator.
func NewGenerator(opts Options) *Generator {
	if opts.Suffix == "" {
		opts.Suffix = ".spanner.go"
	}
	if opts.Language == "" {
		opts.Language = "go"
	}
	if opts.PackageName == "" {
		opts.PackageName = filepath.Base(opts.OutDir)
	}

